namespace ProductApi.Models;

/// <summary>The category a product belongs to.</summary>
public enum Category
{
    Electronics,
    Clothing,
    Food,
    Books
}

namespace ProductApi.Models;

/// <summary>Internal product entity used by the data store.</summary>
internal sealed class Product
{
    public int Id { get; set; }
    public required string Name { get; set; }
    public decimal Price { get; set; }
    public Category Category { get; set; }
    public DateTimeOffset CreatedAt { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace ProductApi.Models;

/// <summary>Payload for creating a new product.</summary>
public sealed record CreateProductRequest
{
    /// <summary>The product name (max 200 characters).</summary>
    [Required, MaxLength(200)]
    public required string Name { get; init; }

    /// <summary>The product price (must be between 0.01 and 999999.99).</summary>
    [Range(0.01, 999999.99)]
    public required decimal Price { get; init; }

    /// <summary>The product category.</summary>
    [Required]
    public required Category Category { get; init; }
}

namespace ProductApi.Models;

/// <summary>Represents a product returned by the API.</summary>
public sealed record ProductResponse(
    int Id,
    string Name,
    decimal Price,
    Category Category,
    DateTimeOffset CreatedAt);

using ProductApi.Models;

namespace ProductApi.Services;

/// <summary>Defines operations for managing products.</summary>
public interface IProductService
{
    Task<IReadOnlyList<ProductResponse>> GetAllAsync(CancellationToken ct);
    Task<ProductResponse?> GetByIdAsync(int id, CancellationToken ct);
    Task<ProductResponse> CreateAsync(CreateProductRequest request, CancellationToken ct);
}

using ProductApi.Models;

namespace ProductApi.Services;

/// <summary>Thread-safe in-memory implementation of <see cref="IProductService"/>.</summary>
internal sealed class InMemoryProductService : IProductService
{
    private readonly Lock _lock = new();
    private readonly List<Product> _products = [];
    private int _nextId = 1;

    public Task<IReadOnlyList<ProductResponse>> GetAllAsync(CancellationToken ct)
    {
        lock (_lock)
        {
            var results = _products.Select(ToResponse).ToList();
            return Task.FromResult<IReadOnlyList<ProductResponse>>(results);
        }
    }

    public Task<ProductResponse?> GetByIdAsync(int id, CancellationToken ct)
    {
        lock (_lock)
        {
            var product = _products.Find(p => p.Id == id);
            return Task.FromResult(product is null ? null : ToResponse(product));
        }
    }

    public Task<ProductResponse> CreateAsync(CreateProductRequest request, CancellationToken ct)
    {
        lock (_lock)
        {
            var product = new Product
            {
                Id = _nextId++,
                Name = request.Name,
                Price = request.Price,
                Category = request.Category,
                CreatedAt = DateTimeOffset.UtcNow
            };

            _products.Add(product);
            return Task.FromResult(ToResponse(product));
        }
    }

    private static ProductResponse ToResponse(Product p) =>
        new(p.Id, p.Name, p.Price, p.Category, p.CreatedAt);
}

using Microsoft.AspNetCore.Http.HttpResults;
using ProductApi.Models;
using ProductApi.Services;

namespace ProductApi.Endpoints;

/// <summary>Maps product-related API endpoints.</summary>
internal static class ProductEndpoints
{
    internal static WebApplication MapProductEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("/api/products")
            .WithTags("Products");

        group.MapGet("/", async Task<Ok<IReadOnlyList<ProductResponse>>> (
            IProductService service, CancellationToken ct) =>
        {
            var products = await service.GetAllAsync(ct);
            return TypedResults.Ok(products);
        })
        .WithName("GetAllProducts")
        .WithSummary("List all products")
        .WithDescription("Returns every product currently stored in the catalog.")
        .Produces<IReadOnlyList<ProductResponse>>(StatusCodes.Status200OK);

        group.MapGet("/{id:int}", async Task<Results<Ok<ProductResponse>, NotFound>> (
            int id, IProductService service, CancellationToken ct) =>
        {
            var product = await service.GetByIdAsync(id, ct);
            return product is null
                ? TypedResults.NotFound()
                : TypedResults.Ok(product);
        })
        .WithName("GetProductById")
        .WithSummary("Get a product by ID")
        .WithDescription("Returns the full product details for the given identifier, or 404 if not found.")
        .Produces<ProductResponse>(StatusCodes.Status200OK)
        .Produces(StatusCodes.Status404NotFound);

        group.MapPost("/", async Task<Created<ProductResponse>> (
            CreateProductRequest request, IProductService service, CancellationToken ct) =>
        {
            var product = await service.CreateAsync(request, ct);
            return TypedResults.Created($"/api/products/{product.Id}", product);
        })
        .WithName("CreateProduct")
        .WithSummary("Create a product")
        .WithDescription("Creates a new product and returns it with a Location header pointing to the new resource.")
        .Produces<ProductResponse>(StatusCodes.Status201Created)
        .Produces(StatusCodes.Status400BadRequest);

        return app;
    }
}

using Microsoft.AspNetCore.Diagnostics;
using Microsoft.AspNetCore.Mvc;

namespace ProductApi.Middleware;

internal sealed class ApiExceptionHandler(ILogger<ApiExceptionHandler> logger)
    : IExceptionHandler
{
    public async ValueTask<bool> TryHandleAsync(
        HttpContext httpContext,
        Exception exception,
        CancellationToken cancellationToken)
    {
        var (statusCode, title) = exception switch
        {
            KeyNotFoundException => (StatusCodes.Status404NotFound, "Not Found"),
            ArgumentException => (StatusCodes.Status400BadRequest, "Bad Request"),
            InvalidOperationException => (StatusCodes.Status409Conflict, "Conflict"),
            _ => (0, (string?)null)
        };

        if (statusCode == 0)
            return false;

        logger.LogWarning(exception, "Handled API exception: {Title}", title);

        httpContext.Response.StatusCode = statusCode;
        await httpContext.Response.WriteAsJsonAsync(new ProblemDetails
        {
            Status = statusCode,
            Title = title,
            Detail = title,
            Instance = httpContext.Request.Path
        }, cancellationToken);

        return true;
    }
}

